SELECT n.notice_id AS noticeId, n.user_no AS userNo, n.notice_title AS title, n.notice_con AS content, n.notice_chk AS noticeChk, n.notice_alert AS noticeAlert, n.notice_file_id AS noticeFileId, DATE_FORMAT(n.regdate, '%Y-%m-%d %H:%i:%s') AS regDt, u.USER_NAME AS regUserName FROM pi_notice n LEFT JOIN pi_user u ON n.user_no = u.USER_NO WHERE 1=1
AND ( n.notice_title LIKE CONCAT('%', #{searchKeyword}, '%') OR n.notice_con LIKE CONCAT('%', #{searchKeyword}, '%') )
ORDER BY n.regdate DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE pi_notice
SET notice_chk = 1
WHERE notice_id = #{noticeId}
